const amqp = require('amqplib');
const { Client } = require('pg'); // Assuming PostgreSQL for database queries

const QUEUE_NAME = 'your_queue_name';
const RABBITMQ_URL = 'amqp://localhost'; // Update with your RabbitMQ URL
const DB_CONFIG = {
  user: 'your_db_user',
  host: 'localhost',
  database: 'your_database',
  password: 'your_db_password',
  port: 5432,
};

async function connectToRabbitMQ() {
  const connection = await amqp.connect(RABBITMQ_URL);
  const channel = await connection.createChannel();
  await channel.assertQueue(QUEUE_NAME, { durable: true });
  return channel;
}

async function connectToDatabase() {
  const client = new Client(DB_CONFIG);
  await client.connect();
  return client;
}

async function processMessage(message) {
  try {
    const content = JSON.parse(message.content.toString());
    const { type, payload } = content;

    if (!type || !payload) {
      throw new Error('Invalid message format');
    }

    switch (type) {
      case 'CREATE':
        await createRecord(payload);
        break;
      case 'UPDATE':
        await updateRecord(payload);
        break;
      case 'DELETE':
        await deleteRecord(payload);
        break;
      default:
        throw new Error('Unknown message type');
    }

    console.log('Processed message:', content);
  } catch (error) {
    console.error('Error processing message:', error);
  }
}

async function createRecord(payload) {
  // Validate and sanitize payload here
  const { name, value } = payload;
  const query = 'INSERT INTO your_table (name, value) VALUES ($1, $2)';
  await dbClient.query(query, [name, value]);
}

async function updateRecord(payload) {
  // Validate and sanitize payload here
  const { id, name, value } = payload;
  const query = 'UPDATE your_table SET name = $1, value = $2 WHERE id = $3';
  await dbClient.query(query, [name, value, id]);
}

async function deleteRecord(payload) {
  // Validate and sanitize payload here
  const { id } = payload;
  const query = 'DELETE FROM your_table WHERE id = $1';
  await dbClient.query(query, [id]);
}

(async () => {
  const channel = await connectToRabbitMQ();
  dbClient = await connectToDatabase();

  channel.consume(QUEUE_NAME, async (message) => {
    if (message !== null) {
      await processMessage(message);
      channel.ack(message);
    }
  });
})();